from browser import Browser
from url import URL

import pytest

def test_requests():
    b = Browser(True)

    body = URL("https://example.com").request()
    assert "Example Domain" in body
    assert body.strip().startswith("<!doctype html")
    assert body.strip().endswith("</html>")

